mapper.select:
SELECT order_no, user_id, product_id, num, amount, status, create_time, update_time
FROM t_order


        AND order_no = #{query.orderNo}



        AND user_id = #{query.userId}




        AND product_id = #{query.productId}



        AND num >= #{query.minNum}


        AND num <= #{query.maxNum}



        AND amount >= #{query.minAmount}


        AND amount <= #{query.maxAmount}



        AND status = #{query.status.code}



        AND create_time >= #{query.startTime}


        AND create_time <= #{query.endTime}



        AND update_time >= #{query.updateStartTime}


        AND update_time <= #{query.updateEndTime}


ORDER BY create_time DESC
